import requests
import json

class RabbitMQManager:
    def __init__(self, username='guest', password='guest', host='localhost', port='15672'):
        self.url = f'http://{host}:{port}/api'
        self.credentials = (username, password)

    def create_vhost(self, vhost_name):
        vhost_url = f'{self.url}/vhosts/{vhost_name}'
        response = requests.put(vhost_url, auth=self.credentials)
        response.raise_for_status()

    def create_user(self, user_name, user_password):
        user_url = f'{self.url}/users/{user_name}'
        user_data = json.dumps({"password": user_password, "tags": ""})
        response = requests.put(user_url, data=user_data, auth=self.credentials)
        response.raise_for_status()

    def set_permissions(self, vhost_name, user_name, perm_dict=None):
        if perm_dict is None:
            perm_dict = {"configure": ".*", "write": ".*", "read": ".*"}
        permissions_url = f'{self.url}/permissions/{vhost_name}/{user_name}'
        permissions_data = json.dumps(perm_dict)
        response = requests.put(permissions_url, data=permissions_data, auth=self.credentials)
        response.raise_for_status()


